import jwt from "jsonwebtoken";

/**
 * Access Controller Middleware
 * Verifies the JWT token and extracts the userId for use in subsequent controllers.
 */
export const accessController = async (req, res, next) => {
    try {
        let token = req.cookies.token;
        if (!token && req.headers.authorization) {
            token = req.headers.authorization.split(" ")[1];
        }

        if (!token) {
            return res.status(401).json({ message: "Access denied. No token provided." });
        }

        token = token.trim(); // Ensure no whitespace
        let verifyToken;
        const secret = process.env.JWT_SECRET || 'secret';
        try {
            verifyToken = jwt.verify(token, secret);
        } catch (error) {
            if (error.name !== "TokenExpiredError") {
                 console.error("--- JWT VERIFICATION FAILED (Email-Marketing) ---");
                 console.error("Message:", error.message);
                 console.error("Secret Info:", process.env.JWT_SECRET ? `From ENV (Length: ${process.env.JWT_SECRET.length}, Prefix: ${process.env.JWT_SECRET.slice(0,3)}...)` : "FALLBACK 'secret'");
                 console.error("Token Prefix:", token.slice(0, 15) + "...");
                 console.error("--------------------------------------------------");
            }
            return res.status(401).json({ message: "Invalid or expired token." });
        }

        req.userId = verifyToken.userId || verifyToken.id;
        next();
    } catch (error) {
        console.error("ACCESS CONTROLLER ERROR:", error.message);
        res.status(500).json({
            message: "An error occurred during authentication.",
            error: error.message
        });
    }
};
